# frozen_string_literal: true

require "fileutils"
require "json"

module Agentkit
  module CLI
    # Generates a complete Rails domain application from a domain_profile.json.
    # Called by the CLI after the Wizard completes, or directly via:
    #   agentkit generate --profile=domain_profile.json
    class Generator
      def initialize(profile)
        @p        = profile
        @app_name = @p["app_name"]
        @entity   = @p["primary_entity"]
        @dir      = @app_name.downcase.gsub(/\s+/, "_")
      end

      def generate
        puts "\n🔨 Generating #{@app_name}...\n"

        create_directory_structure
        write_gemfile
        write_initializer
        write_application_agent
        write_domain_agents
        write_domain_models
        write_seeds
        write_env_example
        write_sidekiq_config
        write_readme

        puts ""
        puts "✅ #{@app_name} generated in ./#{@dir}/"
        puts ""
        puts "Next steps:"
        puts "  cd #{@dir}"
        puts "  cp .env.example .env   # add your API keys"
        puts "  bundle install"
        puts "  rails db:create db:migrate db:seed"
        puts "  bin/dev"
        puts ""
        puts "Estimated setup time: #{setup_time}"
      end

      private

      # ─── Directory structure ───────────────────────────────────────────────

      def create_directory_structure
        dirs = [
          "app/agents",
          "app/models",
          "app/skills",
          "app/views/#{@entity.pluralize}",
          "app/views/agentkit",
          "config/initializers",
          "db/seeds",
          "db/migrate"
        ]
        dirs.each { |d| FileUtils.mkdir_p("#{@dir}/#{d}") }
        puts "  ✓ Directory structure created"
      end

      # ─── Gemfile ──────────────────────────────────────────────────────────

      def write_gemfile
        providers = @p.fetch("llm_providers", ["anthropic"])
        llm_keys = providers.map { |p|
          case p
          when "anthropic" then "  # anthropic - included via ruby_llm"
          when "google"    then "  # google - included via ruby_llm"
          when "openai"    then "  # openai - included via ruby_llm"
          when "ollama"    then "  # ollama - use ruby_llm with ollama adapter"
          end
        }.join("\n")

        write_file("#{@dir}/Gemfile", <<~RUBY)
          # frozen_string_literal: true
          source "https://rubygems.org"
          git_source(:github) { |repo| "https://github.com/\#{repo}.git" }

          ruby "~> 3.3"

          gem "rails",         "~> 8.0"
          gem "pg",            "~> 1.5"
          gem "puma",          "~> 6.0"
          gem "agentkit-rails"  # Agent-first Rails Engine

          # Background jobs
          gem "sidekiq",      "~> 7.0"
          gem "sidekiq-cron", "~> 1.9"

          # Frontend
          gem "turbo-rails"
          gem "stimulus-rails"
          gem "importmap-rails"
          gem "tailwindcss-rails"

          # Auth (choose one)
          gem "devise"      # or sorcery, rodauth, etc.

          # LLM providers (via ruby_llm)
          # #{llm_keys}

          group :development, :test do
            gem "rspec-rails"
            gem "factory_bot_rails"
            gem "dotenv-rails"
          end
        RUBY
        puts "  ✓ Gemfile written"
      end

      # ─── Initializer ──────────────────────────────────────────────────────

      def write_initializer
        mem = @p.fetch("memory", {})
        infra = @p.fetch("infra", {})
        features_str = @p.fetch("features", []).map { |f| ":#{f}" }.join(", ")

        write_file("#{@dir}/config/initializers/agentkit.rb", <<~RUBY)
          # frozen_string_literal: true
          # AgentKit Rails — Domain Initializer
          # Generated by agentkit new — edit to customize

          Agentkit.configure do |config|
            config.domain_name          = "#{@p['app_name']}"
            config.primary_entity       = :#{@entity}

            # ─── LLM Models ──────────────────────────────────────────────────
            config.llm_default_model    = "#{@p.fetch('default_model', 'claude-sonnet-4-6')}"
            config.llm_fast_model       = "#{@p.fetch('fast_model', 'gemini-2.5-flash')}"
            config.llm_complex_model    = "#{@p.fetch('complex_model', 'claude-opus-4-6')}"
            config.llm_code_model       = "#{@p.fetch('default_model', 'claude-sonnet-4-6')}"
            config.embedding_model      = "#{mem.fetch('embedding_model', 'gemini-embedding-2')}"

            # ─── HITL ────────────────────────────────────────────────────────
            # :strict | :advisory | :silent
            config.hitl_level           = :#{@p.fetch('hitl_level', 'strict')}

            # ─── Multi-tenancy ────────────────────────────────────────────────
            config.multi_tenant         = #{infra.fetch('multi_tenant', false)}

            # ─── Memory & Dreaming ────────────────────────────────────────────
            config.dreaming_cron        = "#{mem.fetch('dreaming_cron', '0 2 * * *')}"
            config.dreaming_threshold   = #{mem.fetch('consolidation_threshold', 0.25)}
            config.auto_consolidate     = #{mem.fetch('auto_consolidate', false)}

            # ─── Features ────────────────────────────────────────────────────
            config.features             = [#{features_str}]

            # ─── A2A ─────────────────────────────────────────────────────────
            config.a2a_enabled          = #{infra.fetch('a2a_enabled', false)}
            config.a2a_secret_key       = ENV["AGENTKIT_A2A_KEY"]
            config.mcp_enabled          = #{infra.fetch('mcp_enabled', false)}
          end
        RUBY
        puts "  ✓ config/initializers/agentkit.rb written"
      end

      # ─── Domain ApplicationAgent ──────────────────────────────────────────

      def write_application_agent
        write_file("#{@dir}/app/agents/application_agent.rb", <<~RUBY)
          # frozen_string_literal: true
          # Domain ApplicationAgent — inherits from Agentkit::ApplicationAgent
          # Override domain_context to inject context available to all agents.

          class ApplicationAgent < Agentkit::ApplicationAgent
            # Inject domain-specific context into every agent's system prompt.
            # This method is called by build_context — return a string.
            def domain_context
              parts = []
              parts << "Domain: #{@p['app_name']} — #{@p.fetch('niche', '')}"
              parts << "Primary entity: #{@entity.capitalize}"
              # Add more domain context here, e.g.:
              # parts << "Active #{@entity.pluralize}: \#{#{@entity.capitalize}.active.count}"
              parts.join("\\n")
            end
          end
        RUBY
        puts "  ✓ app/agents/application_agent.rb written"
      end

      # ─── Domain agents ────────────────────────────────────────────────────

      def write_domain_agents
        entity_class = @entity.camelize

        # Intake agent
        write_file("#{@dir}/app/agents/#{@entity}_intake_agent.rb", <<~RUBY)
          # frozen_string_literal: true
          # Generated by AgentKit Wizard — customize as needed

          class #{entity_class}IntakeAgent < ApplicationAgent
            def call(#{@entity})
              memories = recall!("#{@entity} intake \#{#{@entity}.respond_to?(:title) ? #{@entity}.title : ''}")
              ctx      = build_context(query: #{@entity}.respond_to?(:brief) ? #{@entity}.brief : #{@entity}.to_s)

              prompt = <<~PROMPT
                Analyze this new #{@entity} and provide:
                1. Initial risk assessment (low/medium/high)
                2. Key points requiring attention
                3. Recommended next actions

                #{entity_class} details:
                \#{#{@entity}.attributes.slice(*#{@entity}.class.column_names.first(10)).to_json}
              PROMPT

              analysis = chat(prompt, model: :default, system: ctx)

              memorize!(
                analysis,
                tags:       ["intake", "#{@entity}"],
                type:       "observation",
                confidence: 0.8
              )

              suggest!(
                type:        "#{@entity}_review",
                title:       "Initial #{@entity.humanize} analysis ready",
                description: analysis.first(500),
                priority:    "medium",
                suggestable: #{@entity}
              )

              agent_log(event: "completed", payload: { #{@entity}_id: #{@entity}.id })
            end
          end
        RUBY

        # Risk agent
        write_file("#{@dir}/app/agents/#{@entity}_risk_agent.rb", <<~RUBY)
          # frozen_string_literal: true
          # Generated by AgentKit Wizard — customize as needed

          class #{entity_class}RiskAgent < ApplicationAgent
            def call(#{@entity})
              memories = recall!("risk #{@entity}", types: %w[observation insight])
              ctx      = build_context(query: "risk assessment")

              prompt = <<~PROMPT
                Perform a detailed risk assessment for this #{@entity}.
                Consider: timeline, complexity, stakeholders, known risks.
                Return JSON: { risk_level: "low|medium|high|critical", factors: [...], mitigations: [...] }

                #{entity_class}:
                \#{#{@entity}.attributes.to_json}

                Past context:
                \#{memories.map(&:content).join("\\n")}
              PROMPT

              result   = chat(prompt, model: :complex, system: ctx)
              parsed   = JSON.parse(result) rescue { risk_level: "unknown", raw: result }
              priority = %w[high critical].include?(parsed["risk_level"]) ? "high" : "medium"

              suggest!(
                type:        "risk",
                title:       "Risk assessment: \#{parsed['risk_level']&.upcase}",
                description: result.first(1000),
                priority:    priority,
                payload:     parsed,
                suggestable: #{@entity}
              )

              memorize!(
                "Risk assessment for #{@entity}: \#{parsed['risk_level']}",
                tags:       ["risk", "#{@entity}"],
                type:       "observation",
                confidence: 0.75
              )
            end
          end
        RUBY

        # Scope guard agent (if feature enabled)
        if @p.fetch("features", []).include?("scope_guard")
          write_file("#{@dir}/app/agents/scope_guard_agent.rb", <<~RUBY)
            # frozen_string_literal: true
            # Generated by AgentKit Wizard — scope creep detection

            class ScopeGuardAgent < ApplicationAgent
              DRIFT_THRESHOLD = 0.3  # 30% change triggers alert

              def call(#{@entity})
                return unless #{@entity}.respond_to?(:brief) && #{@entity}.brief_previously_changed?

                memories = recall!("original brief #{@entity}", types: ["observation"])
                return if memories.empty?

                prompt = <<~PROMPT
                  Compare the original and current #{@entity} brief.
                  Identify scope changes, additions, or removals.
                  Return JSON: { drift_score: 0.0-1.0, changes: [...], recommendation: "..." }

                  Original: \#{memories.first.content}
                  Current:  \#{#{@entity}.brief}
                PROMPT

                result = chat(prompt, model: :default)
                parsed = JSON.parse(result) rescue {}
                drift  = parsed["drift_score"].to_f

                if drift >= DRIFT_THRESHOLD
                  suggest!(
                    type:        "scope_creep",
                    title:       "Scope drift detected (\#{(drift * 100).round}%)",
                    description: parsed["recommendation"].to_s,
                    priority:    drift >= 0.5 ? "high" : "medium",
                    payload:     parsed,
                    suggestable: #{@entity}
                  )
                end
              end
            end
          RUBY
        end

        puts "  ✓ Domain agents generated"
      end

      # ─── Domain models ────────────────────────────────────────────────────

      def write_domain_models
        entity_class = @entity.camelize
        states       = @p.fetch("lifecycle_states", [])
        triggers     = build_agent_triggers

        write_file("#{@dir}/app/models/#{@entity}.rb", <<~RUBY)
          # frozen_string_literal: true
          # Generated by AgentKit Wizard

          class #{entity_class} < ApplicationRecord
            include Agentkit::AgentTriggerable

            # ─── Associations ────────────────────────────────────────────────
            belongs_to :user
            #{@p.fetch('secondary_entities', []).map { |e| "has_many :#{e.pluralize}" }.join("\n  ")}

            # ─── Validations ─────────────────────────────────────────────────
            validates :title, presence: true

            # ─── State machine ────────────────────────────────────────────────
            #{states.any? ? "validates :status, inclusion: { in: %w[#{states.join(' ')}] }" : "# No lifecycle states configured"}
            #{states.any? ? "scope :active, -> { where(status: '#{states[1] || states[0]}') }" : ""}

            # ─── Agent triggers ───────────────────────────────────────────────
            #{triggers}

            # ─── Scopes ──────────────────────────────────────────────────────
            scope :recent, -> { order(created_at: :desc) }
          end
        RUBY

        # Secondary entities
        @p.fetch("secondary_entities", []).each do |sub|
          sub_class = sub.camelize
          write_file("#{@dir}/app/models/#{sub}.rb", <<~RUBY)
            # frozen_string_literal: true
            # Generated by AgentKit Wizard

            class #{sub_class} < ApplicationRecord
              belongs_to :#{@entity}
              validates :title, presence: true, allow_blank: true
              scope :recent, -> { order(created_at: :desc) }
            end
          RUBY
        end

        puts "  ✓ Domain models generated"
      end

      def build_agent_triggers
        entity_class = @entity.camelize
        triggers     = []
        triggers << "trigger_agent #{entity_class}IntakeAgent, on: :create"
        triggers << "trigger_agent #{entity_class}RiskAgent,   on: :create, async: true"

        if @p.fetch("features", []).include?("scope_guard")
          triggers << "trigger_agent ScopeGuardAgent, on: :update, if: :brief_changed?"
        end

        triggers.join("\n    ")
      end

      # ─── Seeds ────────────────────────────────────────────────────────────

      def write_seeds
        entity_class = @entity.camelize
        industry     = @p.fetch("industry", "general")
        roles        = @p.fetch("user_roles", ["admin", "operador"])

        write_file("#{@dir}/db/seeds/domain_seeds.rb", <<~RUBY)
          # frozen_string_literal: true
          # Domain seeds — generated by AgentKit Wizard
          # Run: rails db:seed

          puts "Seeding #{@app_name}..."

          # ─── Users ────────────────────────────────────────────────────────
          #{roles.map.with_index { |role, i|
            "user_#{i + 1} = User.find_or_create_by!(email: \"#{role}@example.com\") do |u|
            u.password = \"password123\"
            u.role     = \"#{role}\" if u.respond_to?(:role=)
          end"
          }.join("\n\n  ")}

          puts "✓ Users created: #{roles.join(', ')}"

          # ─── Sample #{@entity.humanize.pluralize} ─────────────────────────
          3.times do |i|
            #{@entity} = #{entity_class}.find_or_create_by!(title: "Sample #{@entity.humanize} \#{i + 1}") do |e|
              e.user  = user_1
              e.brief = "This is a sample #{@entity} for #{industry} domain. Item \#{i + 1}." if e.respond_to?(:brief=)
              #{lifecycle_state_seed}
            end
          end

          puts "✓ Sample #{@entity.pluralize} created"
          puts "Seeding complete!"
        RUBY
        puts "  ✓ Seeds written"
      end

      def lifecycle_state_seed
        states = @p.fetch("lifecycle_states", [])
        return "" if states.empty?

        "e.status = \"#{states.first}\" if e.respond_to?(:status=)"
      end

      # ─── .env.example ─────────────────────────────────────────────────────

      def write_env_example
        providers = @p.fetch("llm_providers", ["anthropic"])
        write_file("#{@dir}/.env.example", <<~ENV)
          # AgentKit Rails — Environment Variables
          # Copy to .env and fill in your values

          # Database
          DATABASE_URL=postgresql://localhost/#{@dir}_development

          # Redis (required for Sidekiq)
          REDIS_URL=redis://localhost:6379/0

          # LLM API Keys
          #{providers.include?("anthropic") ? "ANTHROPIC_API_KEY=sk-ant-..." : ""}
          #{providers.include?("google") ? "GOOGLE_API_KEY=AI..." : ""}
          #{providers.include?("openai") ? "OPENAI_API_KEY=sk-..." : ""}
          #{providers.include?("ollama") ? "OLLAMA_BASE_URL=http://localhost:11434" : ""}

          # AgentKit
          AGENTKIT_A2A_KEY=       # Secret key for A2A endpoint auth (leave blank to disable)

          # Rails
          RAILS_ENV=development
          SECRET_KEY_BASE=        # Run: rails secret
        ENV
        puts "  ✓ .env.example written"
      end

      # ─── Sidekiq config ───────────────────────────────────────────────────

      def write_sidekiq_config
        cron = @p.dig("memory", "dreaming_cron") || "0 2 * * *"
        write_file("#{@dir}/config/sidekiq.yml", <<~YAML)
          :concurrency: 5
          :queues:
            - default
            - agentkit_agents
            - agentkit_embeddings
            - agentkit_dreaming
            - agentkit_evolution
            - agentkit_financial
            - agentkit_hitl
        YAML

        write_file("#{@dir}/config/sidekiq_schedule.yml", <<~YAML)
          # Domain-level Sidekiq cron overrides
          agentkit_dreaming:
            cron: "#{cron}"
            class: "Agentkit::DreamingJob"
            queue: agentkit_dreaming
        YAML
        puts "  ✓ Sidekiq config written"
      end

      # ─── README ───────────────────────────────────────────────────────────

      def write_readme
        write_file("#{@dir}/README.md", <<~MD)
          # #{@app_name}

          Generated by [AgentKit Rails](https://github.com/agentkit/agentkit-rails) v#{Agentkit::VERSION}

          **Industry:** #{@p.fetch('industry', 'general')}
          **Primary entity:** #{@entity}
          **HITL level:** #{@p.fetch('hitl_level', 'strict')}

          ## Quick start

          ```bash
          cp .env.example .env    # Add your API keys
          bundle install
          rails db:create db:migrate db:seed
          bin/dev
          ```

          ## Generated agents

          - `#{@entity.camelize}IntakeAgent` — runs on #{@entity} creation
          - `#{@entity.camelize}RiskAgent` — async risk assessment
          #{@p.fetch('features', []).include?('scope_guard') ? "- `ScopeGuardAgent` — detects brief drift on update" : ""}

          ## Features enabled

          #{@p.fetch('features', []).map { |f| "- #{f}" }.join("\n")}

          ## Memory & Dreaming

          - Embedding model: `#{@p.dig('memory', 'embedding_model') || 'gemini-embedding-2'}`
          - Dreaming cron: `#{@p.dig('memory', 'dreaming_cron') || '0 2 * * *'}`
          - Consolidation threshold: #{@p.dig('memory', 'consolidation_threshold') || 0.25}

          ## Domain profile

          See `domain_profile.json` for the full assessment output used to generate this app.
        MD
        puts "  ✓ README.md written"
      end

      # ─── Utilities ────────────────────────────────────────────────────────

      def write_file(path, content)
        FileUtils.mkdir_p(File.dirname(path))
        File.write(path, content)
      end

      def setup_time
        industry = @p.fetch("industry", "otro")
        case industry
        when "legal"      then "2-4 hours"
        when "salud"      then "3-5 hours"
        when "agencia",
             "construccion" then "1-3 hours"
        else "4-8 hours"
        end
      end
    end
  end
end
